  @state SCRIPT_PATH = debug.getinfo(1,'S').source:match[[^@?(.*[\/])[^\/]-$]]  @ 221
  @state CONFIG_GLOBAL_PATH = SCRIPT_PATH .. 'ctm_cfg.txt'  @ 222
  @state take = nil  @ 224
  @state track = nil  @ 225
  @state fire  @ 226   -- installed below, once cm exists
  @state cache = {  @ 228
  @state levels = { 'global', 'project', 'track', 'take', 'transient' }  @ 236
  @state levelSet = {}  @ 238
  @state loaders = {  @ 318
  @state savers = {  @ 326
  @state cm = {}  @ 373

